var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CN No. FRMC001L00767-01-03\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 영상기록","JPN":"CN No. FRMC001L00767-01-03\\n<color=#ffd34c>3級要因</color> 閲覧承認資料\\n付録: 映像記録","ENG":"CN No. FRMC001L00767-01-03\\n<color=#ffd34c>Class 3 Subject</color> Viewing Approval Data\\nAppendix: Video Recording","TWN":"(TWN)CN No. FRMC001L00767-01-03\\n<color=#ffd34c>3급 요인</color> 열람 승인 자료\\n부록: 영상기록"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"저기! 잠시만! 잠시만요!","JPN":"あそこ!少しの間万!少々お待ちください!","ENG":"Hey! Wait! Just a moment!","TWN":"(TWN)저기! 잠시만! 잠시만요!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L4_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"응? 나?","JPN":"うん?私?","ENG":"Huh? Me?","TWN":"(TWN)응? 나?"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아까 침식체 잡은 분 맞죠? 그렇죠?","JPN":"さっき侵食体雑は方当たります?そうです?","ENG":"You're the one who took down that Erosion entity earlier, right? Right?","TWN":"(TWN)아까 침식체 잡은 분 맞죠? 그렇죠?"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"......아.","JPN":"......あ。","ENG":"......Ah.","TWN":"(TWN)......아."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"아하하. 큰일이네. 이런 건 생각 못했는데.","JPN":"アハハ。大変なことだね。このようなことは考えできなかったが。","ENG":"Ahaha. This is bad. I didn't think about this happening.","TWN":"(TWN)아하하. 큰일이네. 이런 건 생각 못했는데."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"맞네, 맞아! 여러분 지금 보고 계시죠?\\n이거 지금 조작도 아무것도 아닙니다! 라이브라고요, 라이브!","JPN":"当たるのね、当たる!皆さん今見ていらっしゃります?\\nこれ今操作も何でもないです!ライブですって、ライブ!","ENG":"That's right, yes! Everyone, you're watching right now, aren't you?\\nThis isn't edited or anything! It's live, I tell you, live!","TWN":"(TWN)맞네, 맞아! 여러분 지금 보고 계시죠?\\n이거 지금 조작도 아무것도 아닙니다! 라이브라고요, 라이브!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"거 참, 얼굴 가리지 말고. 네 덕분에 거기 있던 시민들이 죽다 살았잖아.","JPN":"ことさて、顔選り分けずに。はいおかげでそこのあった市民が死ぬ暮らしたんじゃないの。","ENG":"Come on, don't hide your face. Thanks to you, the civilians there were saved from death.","TWN":"(TWN)거 참, 얼굴 가리지 말고. 네 덕분에 거기 있던 시민들이 죽다 살았잖아."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 내가 나이 더 많은 것 같은데 말 놓을게? 괜찮지?","JPN":"あ、私が年齢さらに多いようであるがぞんざいな言葉使いにするよ?大丈夫なの?","ENG":"Ah, I think I'm older than you, so I'll speak casually? Is that okay?","TWN":"(TWN)아, 내가 나이 더 많은 것 같은데 말 놓을게? 괜찮지?"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"그런 건 상관없는데...... 카메라는 끄면 안 돼?","JPN":"そんなことは構わないが......カメラは消してはいけない?","ENG":"That doesn't matter...... but can't you turn off the camera?","TWN":"(TWN)그런 건 상관없는데...... 카메라는 끄면 안 돼?"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아이, 왜 그러시나. 도시를 구한 영웅께서.\\n시청자들이 얼마나 보고 싶어했는데. ","JPN":"子供、なぜそうするか。都市を求めた英雄が。\\n視聴者がどのくらい見たがったが。","ENG":"Oh, why are you like this. To the hero who saved the city.\\nThe viewers have been wanting to see you so much.","TWN":"(TWN)아이, 왜 그러시나. 도시를 구한 영웅께서.\\n시청자들이 얼마나 보고 싶어했는데. "},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"그냥 운이 좋았어. 더 강한 침식체였으면 다들 위험했을 거야.","JPN":"そのまま運が良かった。さらに強い侵食体だったらみんな危なかったろう。","ENG":"I just got lucky. If it had been a stronger Erosion entity, everyone would have been in danger.","TWN":"(TWN)그냥 운이 좋았어. 더 강한 침식체였으면 다들 위험했을 거야."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그래도 네가 나타나서 막았잖아.\\n아, 잠깐 이거 봐 봐. 시청자들이 이름 좀 알려 달래.","JPN":"でも君が現れて防いだんじゃないの。\\nア、少しこれ見てみる。視聴者が名前ちょっと知らせてヒメニラ。","ENG":"But you appeared and stopped it.\\nAh, wait, look at this. The viewers are asking for your name.","TWN":"(TWN)그래도 네가 나타나서 막았잖아.\\n아, 잠깐 이거 봐 봐. 시청자들이 이름 좀 알려 달래."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"자, 기분이다! 이름이랑 나이! 오늘 PR 마음껏 뽑아 보세요!","JPN":"さあ、気分である!名前と年齢!今日PR思い切り抜いてみてください!","ENG":"Come on, we're feeling it! Name and age! Show off your PR skills to your heart's content today!","TWN":"(TWN)자, 기분이다! 이름이랑 나이! 오늘 PR 마음껏 뽑아 보세요!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"아...... 아하하하.......","JPN":"あ......アハハハ.......","ENG":"Ah...... ahahaha......","TWN":"(TWN)아...... 아하하하......."},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아! 잠깐! 저기요! 잠깐 거기 좀 서 봐요!","JPN":"あ!ちょっと!あのです!少しそこのちょっと立ってみます!","ENG":"Ah! Wait! Hey! Wait, please stop there for a moment!","TWN":"(TWN)아! 잠깐! 저기요! 잠깐 거기 좀 서 봐요!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"미안! 그런 일로 생색 내긴 쑥스러워서!","JPN":"ごめん!そんな事で顔を立てることはきまりが悪くて!","ENG":"Sorry! I'm too shy to boast about something like that!","TWN":"(TWN)미안! 그런 일로 생색 내긴 쑥스러워서!"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이상입니다.","JPN":"以上です。","ENG":"End of recording.","TWN":"(TWN)이상입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"촬영 장소는 ■■■■ 3번가, 영상 촬영 직후 스트릭랜드 양은 도시를 벗어난 것으로 추정됩니다.","JPN":"撮影場所は■■■■ 3番街、映像撮影直後ストリックレンド量は都市を脱したことで推定されます。","ENG":"The filming location is ■■■■ 3rd Street. Immediately after the video was recorded, Ms. Strickland is estimated to have left the city.","TWN":"(TWN)촬영 장소는 ■■■■ 3번가, 영상 촬영 직후 스트릭랜드 양은 도시를 벗어난 것으로 추정됩니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"■■■■라.......","JPN":"■■■■ラ.......","ENG":"■■■■, huh.......","TWN":"(TWN)■■■■라......."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"당시 번화가에 소규모의 하급 침식체 무리가 출몰한 것도 확인되었습니다.","JPN":"当時繁華街に小規模の下級侵食体群れが出没したことも確認されました。","ENG":"It was also confirmed that a small group of low-class Erosion entities appeared in the downtown area at that time.","TWN":"(TWN)당시 번화가에 소규모의 하급 침식체 무리가 출몰한 것도 확인되었습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"시기 좋게 스트릭랜드 양이 막아 줘서 인명 피해는 없었지만요.","JPN":"時期良くストリックレンド量が防いでくれて人命被害はなかったけれども。","ENG":"Fortunately, Ms. Strickland blocked them in time, so there were no casualties.","TWN":"(TWN)시기 좋게 스트릭랜드 양이 막아 줘서 인명 피해는 없었지만요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아우터에서는 검색되지 않는군.\\n격퇴 보고를 안 올린 건가?","JPN":"アウターでは検索されないね。\\n撃退報告を上げないのか?","ENG":"It's not showing up in the Outer search.\\nDid she not file a repulsion report?","TWN":"(TWN)아우터에서는 검색되지 않는군.\\n격퇴 보고를 안 올린 건가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. 스트릭랜드 양이 아니라 지역 경찰청 명의로 검색하셔야 합니다.","JPN":"はい。ストリックレンド量ではなく地域警察庁名義で検索しなければならないです。","ENG":"Correct. You must search under the local police station's name, not Ms. Strickland's.","TWN":"(TWN)네. 스트릭랜드 양이 아니라 지역 경찰청 명의로 검색하셔야 합니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"시체를 내버려 둬서 신고를 받고 출동한 지역 경찰들이 대신 가로챘거든요.\\n남의 공로를 자기 몫으로 돌리고 싶어 안달 난 사람이야 수두룩하니까요.","JPN":"死体をほったらかして申告を受けて出動した地域警察が代わりに横取りしたんですよ。\\n男の功労を寝る分け前で回したくてやきもきする人ならありふれるからです。","ENG":"The local police who received the report and were dispatched because the bodies were left behind took credit for it instead.\\nThere are countless people desperate to claim others' achievements as their own.","TWN":"(TWN)시체를 내버려 둬서 신고를 받고 출동한 지역 경찰들이 대신 가로챘거든요.\\n남의 공로를 자기 몫으로 돌리고 싶어 안달 난 사람이야 수두룩하니까요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"희한하군. 이터니움은 추출하지 않았나.","JPN":"珍しいね。エタニウムは抽出しなかったか。","ENG":"How odd. Did she not extract the Eternium?","TWN":"(TWN)희한하군. 이터니움은 추출하지 않았나."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"추출을 시도한 흔적도, 운반하려 했던 정황도 없었습니다.","JPN":"抽出を試みた跡も、運ぼうとした状況もなかったです。","ENG":"There were no traces of attempting extraction, nor any circumstances suggesting she tried to transport it.","TWN":"(TWN)추출을 시도한 흔적도, 운반하려 했던 정황도 없었습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"목격자에 따르면, 침식체를 격퇴하자마자 사라졌다는군요.","JPN":"目撃者によれば、侵食体を撃退するやいなや消えたと言うのよです。","ENG":"According to witnesses, she disappeared immediately after repelling the Erosion entities.","TWN":"(TWN)목격자에 따르면, 침식체를 격퇴하자마자 사라졌다는군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"흠. 영웅이라도 지망하는 건가.","JPN":"傷。英雄でも志望するのか。","ENG":"Hmm. Does she aspire to be a hero or something.","TWN":"(TWN)흠. 영웅이라도 지망하는 건가."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그런데 나는 말일세, 세상에 대가 없는 선의란 놈이 있다고 믿지 않아.","JPN":"ところで出る言葉だよ、世の中に凄腕ない善意とはものがあると信じない。","ENG":"But you know, I don't believe there's such a thing as goodwill without a price in this world.","TWN":"(TWN)그런데 나는 말일세, 세상에 대가 없는 선의란 놈이 있다고 믿지 않아."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"동의합니다. ","JPN":"同意します。","ENG":"I agree.","TWN":"(TWN)동의합니다. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......하지만 이럴 때마다 차라리 그런 놈이 있길 바라게 되는군.","JPN":"......しかしこのようである度にいっそそんなものがあってほしくなるね。","ENG":"......But every time this happens, I end up hoping that such a person exists.","TWN":"(TWN)......하지만 이럴 때마다 차라리 그런 놈이 있길 바라게 되는군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};